JS render helper (scales + labels):
```javascript
function renderBarChart(svgEl, data) {
  // data: [{label, value}]
  const w = 320, h = 160, padTop = 10, padBot = 30;
  const max = Math.max(...data.map(d => d.value));
  const barW = (w - 20) / data.length - 8;
  svgEl.innerHTML = data.map((d, i) => {
    const barH = ((d.value / max) * (h - padTop - padBot));
    const x = 10 + i * (barW + 8);
    const y = h - padBot - barH;
    return `
      <rect x="${x}" y="${y}" width="${barW}" height="${barH}" fill="var(--accent, #3b82f6)" rx="4"/>
      <text x="${x + barW/2}" y="${h - padBot + 14}" text-anchor="middle" font-size="11" fill="currentColor">${d.label}</text>
      <text x="${x + barW/2}" y="${y - 4}" text-anchor="middle" font-size="10" fill="currentColor" opacity="0.7">${d.value}</text>`;
  }).join('');
}
```

