**DONUT CHART** (categorical share — 2-5 slices):
```html
<svg class="donut" viewBox="0 0 100 100" width="160" height="160">
  <!-- Background ring -->
  <circle cx="50" cy="50" r="40" fill="none" stroke="currentColor" stroke-opacity="0.1" stroke-width="14"/>
  <!-- Slices: stroke-dasharray = arc-length, total-circumference = 2*PI*40 ≈ 251.3 -->
  <circle cx="50" cy="50" r="40" fill="none" stroke="#3b82f6" stroke-width="14" stroke-dasharray="100 151" stroke-dashoffset="0"   transform="rotate(-90 50 50)"/>
  <circle cx="50" cy="50" r="40" fill="none" stroke="#22c55e" stroke-width="14" stroke-dasharray="75 176"  stroke-dashoffset="-100" transform="rotate(-90 50 50)"/>
  <circle cx="50" cy="50" r="40" fill="none" stroke="#f59e0b" stroke-width="14" stroke-dasharray="50 201"  stroke-dashoffset="-175" transform="rotate(-90 50 50)"/>
  <!-- Center label -->
  <text x="50" y="48" text-anchor="middle" font-size="18" font-weight="700" fill="currentColor">$1.2K</text>
  <text x="50" y="62" text-anchor="middle" font-size="9" fill="currentColor" opacity="0.6">Total</text>
</svg>
```
JS helper for donut from `[{label, value, color}]`:
```javascript
function renderDonut(svgEl, slices, totalLabel) {
  const r = 40, C = 2 * Math.PI * r; // ≈251.3
  const total = slices.reduce((s, x) => s + x.value, 0);
  let offset = 0;
  const ringHTML = slices.map(s => {
    const arc = (s.value / total) * C;
    const path = `<circle cx="50" cy="50" r="${r}" fill="none" stroke="${s.color}" stroke-width="14" stroke-dasharray="${arc} ${C - arc}" stroke-dashoffset="${-offset}" transform="rotate(-90 50 50)"/>`;
    offset += arc;
    return path;
  }).join('');
  svgEl.innerHTML = `<circle cx="50" cy="50" r="${r}" fill="none" stroke="currentColor" stroke-opacity="0.1" stroke-width="14"/>${ringHTML}<text x="50" y="48" text-anchor="middle" font-size="16" font-weight="700" fill="currentColor">${totalLabel}</text>`;
}
```

**PROGRESS RING** (circular progress 0-100% — for goals/quotas):
```html
<svg class="ring" viewBox="0 0 80 80" width="80" height="80">
  <circle cx="40" cy="40" r="32" fill="none" stroke="currentColor" stroke-opacity="0.15" stroke-width="6"/>
  <!-- Progress arc: full circumference = 2*PI*32 ≈ 201.06; for 65% set stroke-dasharray="130.7 201" -->
  <circle cx="40" cy="40" r="32" fill="none" stroke="#3b82f6" stroke-width="6" stroke-dasharray="130.7 201" stroke-linecap="round" transform="rotate(-90 40 40)"/>
  <text x="40" y="45" text-anchor="middle" font-size="18" font-weight="700" fill="currentColor">65%</text>
</svg>
```
JS:
```javascript
function setProgressRing(svgEl, percent /* 0-100 */) {
  const C = 2 * Math.PI * 32; // ≈201.06
  const arc = Math.min(100, Math.max(0, percent)) / 100 * C;
  svgEl.querySelector('.progress').setAttribute('stroke-dasharray', `${arc} ${C}`);
  svgEl.querySelector('.progress-label').textContent = `${Math.round(percent)}%`;
}
```

